	const a = lab.y;
	const b = lab.z;
	const l_ = L.add(a.mul(.3963377774)).add(b.mul(.2158037573));
	const m_ = L.sub(a.mul(.1055613458)).sub(b.mul(.0638541728));
	const s_ = L.sub(a.mul(.0894841775)).sub(b.mul(1.291485548));
	const l = pow(l_, float(3));
